// Basic typed function declaration
function add(a: number, b: number): number {
  return a + b;
}

// No return value — use void
function logMessage(message: string): void {
  console.log(message);
}

// Never returns (throws or infinite loop)
function fail(reason: string): never {
  throw new Error(reason);
}

// Calling before the declaration is valid (hoisting)
const result = add(3, 4); // 7

// Function expression
const multiply = function(a: number, b: number): number {
  return a * b;
};

// Arrow function — same signature
const multiply2 = (a: number, b: number): number => a * b;

// Arrow with a block body
const divide = (a: number, b: number): number => {
  if (b === 0) throw new Error('Division by zero');
  return a / b;
};

// this binding difference
class Timer {
  seconds = 0;

  // Arrow — lexical this, safe to pass as callback
  start = () => {
    setInterval(() => this.seconds++, 1000); // this is the Timer instance
  };

  // Regular method — own this, risky to pass as callback
  startRegular() {
    setInterval(function() {
      // this here is undefined (strict mode) or window — NOT the Timer
      // this.seconds++; // would crash
    }, 1000);
  }
}

function greet(name: string, title?: string): string {
  if (title) {
    return `Hello, ${title} ${name}`;
  }
  return `Hello, ${name}`;
}

greet('Alice');           // 'Hello, Alice'
greet('Alice', 'Dr.');    // 'Hello, Dr. Alice'

function paginate(page: number = 1, pageSize: number = 20): string {
  return `Fetching page ${page} of size ${pageSize}`;
}

paginate();        // 'Fetching page 1 of size 20'
paginate(3);       // 'Fetching page 3 of size 20'
paginate(3, 10);   // 'Fetching page 3 of size 10'
paginate(undefined, 50); // 'Fetching page 1 of size 50'

