function sum(...numbers: number[]): number {
  return numbers.reduce((acc, n) => acc + n, 0);
}

sum(1, 2, 3);         // 6
sum(10, 20, 30, 40);  // 100

// With leading required params
function tag(label: string, ...values: string[]): string {
  return `[${label}] ${values.join(', ')}`;
}

tag('INFO', 'user logged in', 'session started');
// '[INFO] user logged in, session started'

// Overload signatures (no body)
function format(value: string): string;
function format(value: number, decimals: number): string;
function format(value: Date): string;

// Implementation signature — must be compatible with all overloads
function format(value: string | number | Date, decimals?: number): string {
  if (typeof value === 'string') return value.trim();
  if (typeof value === 'number') return value.toFixed(decimals ?? 2);
  return value.toISOString();
}

format('  hello  ');    // 'hello'
format(3.14159, 2);     // '3.14'
format(new Date());     // ISO string

// Angular use-case: observable vs promise overload
function toAsync(obs: Observable<string>): Promise<string>;
function toAsync(obs: Observable<number>): Promise<number>;
function toAsync(obs: Observable<any>): Promise<any> {
  return firstValueFrom(obs);
}

// Function type alias
type Predicate<T> = (value: T) => boolean;
type Transform<T, U> = (value: T) => U;
type EventHandler<E> = (event: E) => void;

// Using a function type as a parameter
function filter<T>(items: T[], predicate: Predicate<T>): T[] {
  return items.filter(predicate);
}

const evens = filter([1, 2, 3, 4, 5], n => n % 2 === 0); // [2, 4]

// Function type in an interface
interface Logger {
  log: (message: string) => void;
  error: (message: string, error?: unknown) => void;
}

// Angular: typed event emitter callbacks
type ClickHandler = (event: MouseEvent) => void;

@Component({ selector: 'app-btn', template: '<button (click)="onClick($event)">Click</button>' })
class BtnComponent {
  @Output() clicked = new EventEmitter<MouseEvent>();

  onClick: ClickHandler = (event) => {
    this.clicked.emit(event);
  };
}

// Basic generic function
function identity<T>(value: T): T {
  return value;
}

identity<string>('hello');   // type: string
identity(42);                // type inferred as number

// Generic with constraint
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

const user = { name: 'Alice', age: 30 };
getProperty(user, 'name');  // string
getProperty(user, 'age');   // number
// getProperty(user, 'email'); // TS error — 'email' not in keyof typeof user

// Generic array utilities — common in Angular services
function first<T>(items: T[]): T | undefined {
  return items[0];
}

function groupBy<T, K extends string | number>(
  items: T[],
  key: (item: T) => K
): Record<K, T[]> {
  return items.reduce((acc, item) => {
    const k = key(item);
    (acc[k] ??= []).push(item);
    return acc;
  }, {} as Record<K, T[]>);
}

// Angular service pattern
@Injectable({ providedIn: 'root' })
class CacheService {
  get<T>(key: string): T | null {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) as T : null;
  }

  set<T>(key: string, value: T): void {
    localStorage.setItem(key, JSON.stringify(value));
  }
}

