import { Component, OnInit, OnDestroy, inject } from '@angular/core';
import { Subject, takeUntil } from 'rxjs';
import { UserService } from './user.service';

interface User {
  id: number;
  name: string;
  email: string;
}

@Component({ selector: 'app-user-list', template: '' })
export class UserListComponent implements OnInit, OnDestroy {
  private readonly userService = inject(UserService);
  private readonly destroy$ = new Subject<void>();

  users: User[] = [];
  loading = false;

  // Lifecycle hook — void return, no parameters
  ngOnInit(): void {
    this.loadUsers();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  // Private method — explicit return type avoids accidental Observable leak
  private loadUsers(): void {
    this.loading = true;
    this.userService
      .getAll()
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (users: User[]) => {
          this.users = users;
          this.loading = false;
        },
        error: (err: unknown) => {
          console.error(err);
          this.loading = false;
        },
      });
  }

  // Template-called method — typed event parameter
  onUserClick(user: User): void {
    console.log('Selected:', user.name);
  }

  // Pure transformation — can be a static function
  static sortByName(users: User[]): User[] {
    return [...users].sort((a, b) => a.name.localeCompare(b.name));
  }
}

// Return type Promise<User> means every return must be User
async function fetchUser(id: number): Promise<User> {
  const res = await fetch(`/api/users/${id}`);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json() as Promise<User>;
}

// Awaiting in Angular service
@Injectable({ providedIn: 'root' })
class AuthService {
  async login(email: string, password: string): Promise<void> {
    const token = await this.api.post<{ token: string }>(
      '/auth/login',
      { email, password }
    );
    localStorage.setItem('token', token.token);
  }

  async logout(): Promise<void> {
    await this.api.post<void>('/auth/logout', {});
    localStorage.removeItem('token');
  }
}

// Error handling with typed catch
async function loadData(): Promise<string[]> {
  try {
    return await fetchStrings();
  } catch (err: unknown) {
    // err is unknown — must narrow before use
    if (err instanceof Error) {
      console.error(err.message);
    }
    return [];
  }
}

