// Custom higher-order function
function once<T extends (...args: any[]) => any>(fn: T): T {
  let called = false;
  let result: ReturnType<T>;
  return function (...args: Parameters<T>) {
    if (!called) { called = true; result = fn(...args); }
    return result;
  } as T;
}

const init = once((config: { apiUrl: string }) => {
  console.log('Initialised with', config.apiUrl);
});

init({ apiUrl: 'https://api.example.com' }); // runs
init({ apiUrl: 'https://api.example.com' }); // no-op

// Type guard function
function isString(value: unknown): value is string {
  return typeof value === 'string';
}

function process(input: string | number | null): void {
  if (isString(input)) {
    // TypeScript narrows input to string here
    console.log(input.toUpperCase());
  }
}

// More complex guard — checks object shape
interface ApiError {
  code: number;
  message: string;
}

function isApiError(err: unknown): err is ApiError {
  return (
    typeof err === 'object' &&
    err !== null &&
    'code' in err &&
    'message' in err &&
    typeof (err as ApiError).code === 'number'
  );
}

// Angular HTTP error interceptor
intercept(req: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
  return next.handle(req).pipe(
    catchError((err: unknown) => {
      if (isApiError(err)) {
        // TypeScript knows err.code and err.message are here
        this.notify.error(`Error ${err.code}: ${err.message}`);
      }
      return throwError(() => err);
    })
  );
}

// Pure transformation functions — easy to unit test
function formatCurrency(
  amount: number,
  currency: string = 'USD',
  locale: string = 'en-US'
): string {
  return new Intl.NumberFormat(locale, {
    style: 'currency',
    currency,
  }).format(amount);
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function paginate<T>(items: T[], page: number, size: number): T[] {
  const start = (page - 1) * size;
  return items.slice(start, start + size);
}

// Jasmine unit tests — type-safe
describe('formatCurrency', () => {
  it('formats USD by default', () => {
    expect(formatCurrency(1234.5)).toBe('$1,234.50');
  });

  it('formats EUR', () => {
    expect(formatCurrency(99.9, 'EUR', 'de-DE')).toContain('€');
  });
});

describe('clamp', () => {
  it('returns min when value is below range', () => {
    expect(clamp(-5, 0, 100)).toBe(0);
  });
  it('returns max when value is above range', () => {
    expect(clamp(200, 0, 100)).toBe(100);
  });
});

// Consistent Angular service pattern
@Injectable({ providedIn: 'root' })
export class ProductService {
  private readonly http = inject(HttpClient);
  private readonly apiUrl = '/api/products';

  getAll(): Observable<Product[]> {
    return this.http.get<Product[]>(this.apiUrl);
  }

  getById(id: number): Observable<Product> {
    return this.http.get<Product>(`${this.apiUrl}/${id}`);
  }

  create(product: Omit<Product, 'id'>): Observable<Product> {
    return this.http.post<Product>(this.apiUrl, product);
  }

  update(id: number, changes: Partial<Product>): Observable<Product> {
    return this.http.patch<Product>(`${this.apiUrl}/${id}`, changes);
  }

  delete(id: number): Observable<void> {
    return this.http.delete<void>(`${this.apiUrl}/${id}`);
  }
}
